module RefModule (
  output zero
);

  assign zero = 1'b0;

endmodule

module RefModule (
  output out
);

  assign out = 1'b0;

endmodule

module RefModule (
  output one
);

  assign one = 1'b1;

endmodule

module RefModule (
  input [31:0] in,
  output [31:0] out
);

  assign out = {in[7:0], in[15:8], in[23:16], in[31:24]};

endmodule

module RefModule (
  input in,
  output out
);

  assign out = ~in;

endmodule
